# tools/search.py
import httpx
from typing import Any

class SearchError(Exception):
    pass

def search_web(query: str, max_results: int = 5) -> list[dict[str, Any]]:
    """Return up to max_results web results for query.

    Raises ValueError on invalid inputs; raises SearchError when the
    upstream API returns a non-200 status code.
    """
    if not query or not query.strip():
        raise ValueError("query cannot be empty")
    if not (1 <= max_results <= 50):
        raise ValueError(f"max_results must be 1-50, got {max_results}")

    resp = httpx.get(
        "https://api.search.example.com/v1/search",
        params={"q": query, "n": max_results},
        timeout=10.0,
    )
    if resp.status_code != 200:
        raise SearchError(f"Search API returned {resp.status_code}")
    return resp.json()["results"]


