import pytest
from unittest.mock import patch, MagicMock
from tools.search import search_web, SearchError


class TestSearchWebValidation:
    """Input-contract tests — no network, no mocking needed."""

    def test_raises_on_empty_string(self):
        with pytest.raises(ValueError, match="empty"):
            search_web("")

    def test_raises_on_whitespace_only(self):
        with pytest.raises(ValueError, match="empty"):
            search_web("   ")

    def test_raises_when_max_results_is_zero(self):
        with pytest.raises(ValueError, match="max_results"):
            search_web("python", max_results=0)

    def test_raises_when_max_results_exceeds_50(self):
        with pytest.raises(ValueError, match="max_results"):
            search_web("python", max_results=51)

    @pytest.mark.parametrize("n", [1, 5, 50])
    def test_accepts_valid_max_results(self, n):
        with patch("tools.search.httpx.get") as mock_get:
            mock_get.return_value = MagicMock(
                status_code=200,
                json=lambda: {"results": []}
            )
            result = search_web("python", max_results=n)
            assert isinstance(result, list)
            _, kwargs = mock_get.call_args
            assert kwargs["params"]["n"] == n


class TestSearchWebNetworkBehavior:
    """Behavior tests with a stubbed HTTP client."""

    @patch("tools.search.httpx.get")
    def test_returns_result_list(self, mock_get):
        mock_get.return_value = MagicMock(
            status_code=200,
            json=lambda: {
                "results": [
                    {"title": "Python docs", "url": "https://docs.python.org",
                     "snippet": "Official Python documentation."}
                ]
            },
        )
        results = search_web("python", max_results=1)
        assert len(results) == 1
        assert results[0]["url"] == "https://docs.python.org"

    @patch("tools.search.httpx.get")
    def test_raises_search_error_on_non_200(self, mock_get):
        mock_get.return_value = MagicMock(status_code=429)
        with pytest.raises(SearchError, match="429"):
            search_web("python")

