import re
import json
from datetime import date

def build_system_prompt(
    persona: str,
    tools: list[str],
    today: str | None = None,
) -> str:
    """Assemble the system prompt from its constituent parts."""
    if today is None:
        today = date.today().isoformat()

    parts = [persona.rstrip(), f"Today's date is {today}."]
    if tools:
        tools_block = "\n".join(f"  - {name}" for name in tools)
        parts.append(f"Available tools:\n{tools_block}")
    return "\n\n".join(parts)


_JSON_FENCE = re.compile(r"```json\s*([\s\S]+?)\s*```", re.MULTILINE)

def parse_structured_output(raw: str) -> dict:
    """Extract the first JSON code-fence from an LLM response.

    Raises ValueError with a descriptive message so callers can implement
    a retry strategy (e.g., ask the model to reformat its answer).
    """
    match = _JSON_FENCE.search(raw)
    if not match:
        raise ValueError(f"No JSON block found in model output: {raw[:200]!r}")
    try:
        return json.loads(match.group(1))
    except json.JSONDecodeError as exc:
        raise ValueError(f"Invalid JSON in model output: {exc}") from exc


