import pytest
from agent.prompts import build_system_prompt, parse_structured_output


class TestBuildSystemPrompt:
    def test_includes_persona(self):
        prompt = build_system_prompt("You are a researcher.", tools=[], today="2026-07-10")
        assert "You are a researcher." in prompt

    def test_includes_date(self):
        prompt = build_system_prompt("x", tools=[], today="2026-07-10")
        assert "2026-07-10" in prompt

    def test_tool_names_appear_when_provided(self):
        prompt = build_system_prompt("x", tools=["search_web", "read_file"], today="2026-01-01")
        assert "search_web" in prompt
        assert "read_file" in prompt

    def test_no_tool_section_when_empty_list(self):
        prompt = build_system_prompt("x", tools=[], today="2026-01-01")
        assert "Available tools" not in prompt

    def test_default_date_is_today(self, monkeypatch):
        import agent.prompts as prompts_module
        from unittest.mock import MagicMock
        fake_date = MagicMock()
        fake_date.today.return_value.isoformat.return_value = "2099-01-01"
        monkeypatch.setattr(prompts_module, "date", fake_date)
        prompt = build_system_prompt("x", tools=[])
        assert "2099-01-01" in prompt


class TestParseStructuredOutput:
    def test_parses_valid_json_fence(self):
        raw = 'Here is the result:\n```json\n{"action": "search", "query": "AI"}\n```'
        result = parse_structured_output(raw)
        assert result == {"action": "search", "query": "AI"}

    def test_raises_value_error_when_no_fence(self):
        with pytest.raises(ValueError, match="No JSON block"):
            parse_structured_output("I cannot help with that.")

    def test_raises_value_error_on_malformed_json(self):
        with pytest.raises(ValueError, match="Invalid JSON"):
            parse_structured_output("```json\n{broken\n```")

    def test_ignores_text_before_and_after_fence(self):
        raw = (
            "Sure, here you go:\n"
            "```json\n{\"status\": \"done\"}\n```\n"
            "Let me know if you need anything else."
        )
        assert parse_structured_output(raw) == {"status": "done"}

    @pytest.mark.parametrize("raw,expected", [
        ('```json\n{\"a\": 1}\n```', {"a": 1}),
        ('```json\n{\"x\": [1,2,3]}\n```', {"x": [1, 2, 3]}),
    ])
    def test_parametrized_valid_cases(self, raw, expected):
        assert parse_structured_output(raw) == expected

