import ast
import operator

_SAFE_OPS = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.Div: operator.truediv,
    ast.Pow: operator.pow,
    ast.USub: operator.neg,
}

def evaluate_expression(expr: str) -> float:
    """Safely evaluate a simple arithmetic expression.

    Only allows numeric literals and the operators +, -, *, /, **.
    Raises ValueError for disallowed syntax.
    """
    expr = expr.strip()
    if len(expr) > 200:
        raise ValueError("Expression too long")
    try:
        tree = ast.parse(expr, mode="eval")
    except SyntaxError as exc:
        raise ValueError(f"Invalid expression: {exc}") from exc
    return _eval_node(tree.body)

def _eval_node(node):
    if isinstance(node, ast.Constant) and isinstance(node.value, (int, float)):
        return float(node.value)
    if isinstance(node, ast.BinOp) and type(node.op) in _SAFE_OPS:
        left = _eval_node(node.left)
        right = _eval_node(node.right)
        return _SAFE_OPS[type(node.op)](left, right)
    if isinstance(node, ast.UnaryOp) and type(node.op) in _SAFE_OPS:
        return _SAFE_OPS[type(node.op)](_eval_node(node.operand))
    raise ValueError(f"Disallowed expression node: {type(node).__name__}")


# tests/unit/test_calculator.py
import pytest
from tools.calculator import evaluate_expression

@pytest.mark.parametrize("expr,expected", [
    ("2 + 3",        5.0),
    ("10 - 4",       6.0),
    ("3 * 7",       21.0),
    ("10 / 4",       2.5),
    ("2 ** 8",     256.0),
    ("-5",           -5.0),
    ("(1 + 2) * 3",  9.0),
])
def test_evaluate_expression_valid(expr, expected):
    assert evaluate_expression(expr) == pytest.approx(expected)

def test_evaluate_expression_rejects_import():
    with pytest.raises(ValueError):
        evaluate_expression("__import__('os').system('ls')")

def test_evaluate_expression_rejects_string():
    with pytest.raises(ValueError):
        evaluate_expression("'hello'")

def test_evaluate_expression_rejects_too_long():
    with pytest.raises(ValueError, match="too long"):
        evaluate_expression("1 + " * 100 + "1")

def test_evaluate_expression_division_by_zero():
    # Python raises ZeroDivisionError; the tool does not need to catch it —
    # document this as the expected behaviour.
    with pytest.raises(ZeroDivisionError):
        evaluate_expression("1 / 0")
